import {useCallback, useEffect, useMemo, useRef} from 'react';
import {type FieldValues, useController, useFormContext, type UseFormReturn} from 'react-hook-form';
import {Schema} from 'yup';

// Assuming your types are consolidated in a central file.
import type {
    IElementStyle,
    IFormElement,
    ILabelElement,
    ITextFieldProps,
    LogicFunction,
    UseFieldLogicProps,
    UseFieldLogicReturn
} from '@lmb-it/kitsconcerto-types';
import {dynamicList} from "../utils";
import _ from "lodash";

// --- Hook Return Value ---

/**
 * The core logic engine for an individual form field.
 * This hook replaces LogicContext and FormFieldContext. It watches dependencies,
 * calculates all dynamic properties (visibility, disabled state, required status, etc.),
 * and provides the necessary props from react-hook-form.
 *
 * @param {UseFieldLogicProps<T>} props - The element definition and form control.
 * @returns {UseFieldLogicReturn<T>} An object containing all necessary props and states for rendering the field.
 */
export const useFieldLogic = <T extends FieldValues>({
                                                         element: {onDepsChange, ...element},
                                                         control,
                                                         getValues,
                                                         isFocused,
                                                         groupField,
                                                         watchedValues
                                                     }: UseFieldLogicProps<T>): UseFieldLogicReturn<T> => {


        const formContext = useFormContext<T>()

        const prevDepsRef = useRef<string>("");

        const watchedSig = useMemo(() => JSON.stringify(watchedValues), [watchedValues]);

        const allFormValues = useMemo(() => getValues(), [getValues, watchedSig]);

        /*const watchedObject = useMemo(() => {
            return dependencies.reduce((acc, dep, index) => {
                acc[dep] = watchedValues[index];
                return acc;
            }, {} as any)
        }, [watchedValues, dependencies])*/

        const childElements = useMemo(() => {
            if (!('elements' in element)) {
                return [];
            }
            const elements = element.elements;
            if (typeof elements === 'function') {
                return (elements as LogicFunction<T>)(watchedValues, allFormValues, {
                    control,
                    getValues,
                    setValue: formContext.setValue
                } as any, groupField);
            }
            return elements;
        }, [watchedValues])

        const resolvedProps = useMemo(() => {
            const getDynamicProp = (propName: keyof IFormElement<T> | string) => {
                const propValue: LogicFunction<T> = (element as any)[propName];
                if (typeof propValue === 'function') {
                    return propValue(watchedValues, allFormValues, formContext, groupField);
                }
                return propValue;
            };

            return {
                helperText: getDynamicProp('helperText'),
                leftAddon: getDynamicProp('leftAddon'),
                rightAddon: getDynamicProp('rightAddon'),
                keyFilter: getDynamicProp('keyFilter') as ITextFieldProps<T>['keyFilter'],
                withMask: getDynamicProp('withMask'),
                // ... resolve other dynamic props here
            };
        }, [watchedValues, allFormValues, element, control, getValues]);

        const lastListRef = useRef<T[] | undefined>(undefined);
        const lastElementRef = useRef<any>(null);
        const lastWatchedRef = useRef<any>(null);

        const list = useMemo(() => {
            if (!("list" in element)) return undefined;

            const elementChanged = !_.isEqual(lastElementRef.current, element);
            const watchedChanged = !_.isEqual(lastWatchedRef.current, watchedValues);

            // ✅ nothing meaningful changed → reuse
            if (!elementChanged && !watchedChanged) {
                return lastListRef.current;
            }

            // 🔁 rebuild
            const nextList = dynamicList<T>(
                element,
                watchedValues,
                allFormValues,
                groupField,
                formContext
            );

            lastElementRef.current = element;
            lastWatchedRef.current = watchedValues;
            lastListRef.current = nextList;

            return nextList;
        }, [watchedValues, allFormValues, control, getValues, element]);

        // 4. Centralize dynamic property calculations using memoization.
        const isShown = useMemo(() => {
            // console.log({watchedObject, allFormValues})
            const showLogic = element.show || element.logic?.show;
            if (typeof showLogic === 'function') {
                return (showLogic as LogicFunction<T>)(watchedValues, allFormValues, {
                    control,
                    getValues,
                    setValue: formContext.setValue
                } as any, groupField);
            }
            return true;
        }, [watchedValues, allFormValues, control, getValues, element]);

        const isDisabled = useMemo(() => {
            const disableLogic = element.isDisabled || element.logic?.disable;
            if (typeof disableLogic === 'function') {
                return (disableLogic as LogicFunction<T, boolean>)(watchedValues, allFormValues, {
                    control,
                    getValues,
                    setValue: formContext.setValue
                } as any, groupField);
            }
            return !!disableLogic;
        }, [watchedValues, allFormValues, control, getValues, element]);

        const isRequired = useMemo(() => {
            if (!('schema' in element) || !element.schema) return false;

            const schema = element.schema as Schema<any>;

            const checkRequired = (schema: Schema<any>, parentValues: any): boolean => {
                try {
                    const type = (schema as any)._type;

                    const testValue = (() => {
                        switch (type) {
                            case 'array':
                                return [];
                            case 'object':
                                return {};
                            case 'boolean':
                                return undefined;
                            case 'number':
                                return undefined;
                            case 'date':
                                return undefined;
                            default:
                                return ''; // string or unknown
                        }
                    })();
                    // Try validating an empty string
                    schema.validateSync(
                        testValue, // simulating the field is empty
                        {
                            context: parentValues,
                            // @ts-ignore
                            parent: parentValues,
                            abortEarly: false,
                        }
                    );

                    return false; // Passed even when empty => not required
                } catch (err: any) {
                    // if (element.id === 'count/ries') {
                    //     console.log(err.inner || err);
                    // }

                    if (err?.inner?.length) {
                        return err.inner.some(
                            (e: any) =>
                                e.type === 'required' ||
                                e.message?.toLowerCase().includes('required')
                        );
                    }

                    return (
                        err?.type === 'required' ||
                        err?.message?.toLowerCase().includes('required')
                    );
                }
            };

            // Get the parent object (either group or full form)
            const parent = groupField && groupField.index !== undefined
                ? getValues?.()?.[groupField.name]?.[groupField.index]
                : getValues?.();

            return checkRequired(schema, parent);
        }, [element, watchedValues, allFormValues]);

        const label = useMemo(() => {
            if (typeof element.label === 'function') {
                return (element.label as LogicFunction<T, ILabelElement>)(watchedValues, allFormValues, {
                    control,
                    getValues,
                    setValue: formContext.setValue
                } as any, groupField);
            }
            return element.label;
        }, [watchedValues, allFormValues, control, getValues, element]);

        const placeholder = useMemo(() => {
            if ('placeholder' in element && typeof element.placeholder === 'function') {
                return (element.placeholder as LogicFunction<T, string>)(watchedValues, allFormValues, {
                    control,
                    getValues,
                    setValue: formContext.setValue
                } as any, groupField);
            }
            return ('placeholder' in element ? element.placeholder : undefined) as string | undefined;
        }, [watchedValues, allFormValues, control, getValues, element]);

        const resolvedStyle = useMemo(() => {
            const s = 'style' in element ? element.style : undefined;

            if (s && typeof s === 'function') {
                return s(watchedValues, allFormValues, {
                    control,
                    getValues,
                    setValue: formContext.setValue
                } as any, groupField);
            }
            return s;
        }, [watchedValues, allFormValues, control, getValues, element])

        /**
         * Merge explicit `slots` with `style` sub-keys.
         * IElementStyle sub-keys are bridged into the slot system so they
         * flow through useComponentDefaults → elementStyles → KitsContainer.
         * Priority: style sub-keys (lowest) < explicit slots (highest).
         */
        const slots = useMemo(() => {
            // 1. Resolve explicit slots (DynamicValue)
            const rawSlots = 'slots' in element ? element.slots : undefined;
            let explicitSlots: Record<string, { props?: any; style?: any }> | undefined;
            if (rawSlots && typeof rawSlots === 'function') {
                explicitSlots = (rawSlots as any)(watchedValues, allFormValues, {
                    control,
                    getValues,
                    setValue: formContext.setValue
                } as any, groupField);
            } else {
                explicitSlots = rawSlots as any;
            }

            // 2. Bridge IElementStyle sub-keys into slot format
            if (!resolvedStyle && !explicitSlots) return undefined;
            if (!resolvedStyle) return explicitSlots;

            const STYLE_TO_SLOT: Record<string, string> = {
                input: 'root',
                container: 'container',
                label: 'label',
                helperText: 'helperText',
                errorMessage: 'error',
            };

            const result: Record<string, { props?: any; style?: any }> = {};

            // First layer: style sub-keys (lower priority)
            for (const [styleKey, slotKey] of Object.entries(STYLE_TO_SLOT)) {
                const val = (resolvedStyle as any)[styleKey];
                if (val) {
                    result[slotKey] = { style: val };
                }
            }

            // Second layer: explicit slots override
            if (explicitSlots) {
                for (const [key, slot] of Object.entries(explicitSlots)) {
                    if (!result[key]) {
                        result[key] = slot;
                    } else {
                        result[key] = {
                            ...slot,
                            style: { ...result[key].style, ...(slot.style || {}) },
                        };
                    }
                }
            }

            return Object.keys(result).length > 0 ? result : undefined;
        }, [watchedValues, allFormValues, control, getValues, element, resolvedStyle])

        // 6. Calculate layout properties.
        const layout = useMemo(() => {
            const getDynamicProp = (prop: any) => typeof prop === 'function'
                ? prop(watchedValues, allFormValues, {control, getValues})
                : prop;

            return {
                colSpan: getDynamicProp(element.logic?.colSpan ?? element.colSpan) ?? 12,
                rowSpan: getDynamicProp(element.rowSpan),
                columnGap: getDynamicProp(element.columnGap),
                rowGap: getDynamicProp(element.rowGap),
                colOffset: getDynamicProp(element.colOffset),
                area: getDynamicProp(element.area),
            };
        }, [watchedValues, allFormValues, control, getValues, element]);


        const onWatchedValuesChange = useCallback(() => {
            if (onDepsChange) {
                onDepsChange(watchedValues, allFormValues, formContext as UseFormReturn<T>, groupField)
            }
        }, [watchedValues])

        // 7. Get the field's state and methods from react-hook-form.
        // For Object elements, default to {} so react-hook-form treats the field
        // as a nested object — children register with dot-notation paths
        // (e.g. contactPhone.phoneNumber) and build the nested structure.
        const isObjectElement = element.type === 'Object';
        const {field, fieldState} = useController({
            name: element.id as any,
            control,
            shouldUnregister: !isShown,
            ...(isObjectElement ? {defaultValue: {} as any} : {}),
        });

        useEffect(() => {
            if (!onDepsChange) return;

            // Create a stable signature for watched values
            // (stringify is fine here because deps lists are small)
            const sig = JSON.stringify(watchedValues);

            if (sig === prevDepsRef.current) return; // ✅ no real change

            prevDepsRef.current = sig;

            onDepsChange(watchedValues, allFormValues, formContext as UseFormReturn<T>, groupField);
        }, [onDepsChange, watchedValues, allFormValues, formContext, groupField]);

        // 8. Return a single, clean object for the UI component.
        return {
            field: {
                ...field,
                onChange: (event) => {
                    if ('onChangeValue' in element && element?.onChangeValue) {
                        const value = event != null && typeof event === 'object' && 'target' in event
                            ? event.target.value
                            : event;
                        element.onChangeValue(
                            value,
                            {...fieldState, isFocused: !!isFocused},
                            formContext
                        )
                    }
                    field.onChange(event)
                }
            },
            fieldState,
            watchedValues,
            onWatchedValuesChange,
            elements: childElements,
            isShown,
            isDisabled,
            isRequired,
            hideError: element.hideError,
            label,
            placeholder,
            formContext,
            layout,
            list,
            style: resolvedStyle as IElementStyle,
            slots,
            ...resolvedProps,
            localProps: 'localProps' in element ? element?.localProps : undefined,
            attached: element.attached,
            animation: element.animation,
        };
    }
;
